import React, { useState } from "react";
import "../styles/SupportChat.css";

function SupportChat() {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "I’m here with you. You are not alone. Tell me what’s going on."
    }
  ]);
  const [input, setInput] = useState("");

  const crisisKeywords = [
    "suicide",
    "kill myself",
    "end my life",
    "want to die",
    "dying",
    "self harm"
  ];

  const handleSend = () => {
    if (!input.trim()) return;

    const isCrisis = crisisKeywords.some(word =>
      input.toLowerCase().includes(word)
    );

    setMessages(prev => [
      ...prev,
      { sender: "user", text: input },
      {
        sender: "bot",
        text: isCrisis
          ? "I’m really glad you spoke up. You matter. What you’re feeling can change, even if it doesn’t feel like it right now. Please consider reaching out to someone you trust or a helpline."
          : "I’m listening. Take your time and tell me more."
      }
    ]);

    setInput("");
  };

  return (
    <div className="support-chat-page">
      <div className="support-chat-card">

        <h2>🧠 Support Chat</h2>
        <p className="subtitle">
          Safe space. No judgement. Real support.
        </p>

        <div className="chat-window">
          {messages.map((msg, index) => (
            <div key={index} className={`bubble ${msg.sender}`}>
              {msg.text}
            </div>
          ))}
        </div>

        <div className="chat-input">
          <input
            value={input}
            onChange={e => setInput(e.target.value)}
            placeholder="Type how you’re feeling..."
            onKeyDown={e => e.key === "Enter" && handleSend()}
          />
          <button onClick={handleSend}>Send</button>
        </div>

      </div>
    </div>
  );
}

export default SupportChat;
